var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 느려요. 너무 느립니다.","JPN":"ふふ、遅い。遅すぎです。","ENG":"Hah hah. Nice try, but you’re too slow.","TWN":"嘿嘿～太慢了，太慢了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"박력은 넘치지만, 움직임이 단순하군요.","JPN":"迫力は溢れていますが、動きが単純ですね。","ENG":"You’ve got power, but your movements are too predictable.","TWN":"氣勢很足，但動作很容易被看破。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"이 일대는 전부 처리한 것 같습니다.","JPN":"この一帯はすべて片付けたようです。","ENG":"I think we’ve killed every last one of them here.","TWN":"這附近的好像都解決了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"대결할 만한 상대가 없는 게 아쉽군요.","JPN":"対決できそうな相手がいないのが残念ですね。","ENG":"What a shame there wasn’t a worthy foe to duel this time.","TWN":"沒一個值得一戰的對手，真是遺憾啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"인간이 쳐들어온다고 해서 왔지만, 정작 인간 형상을 베낀 듯한 이런 흉물들뿐이라니.","JPN":"人間が攻撃してきたと言って来てみましたが、人間の形をしているこの醜いものだけだとは。","ENG":"I was excited to hear the humans have attacked, but only to be let down by these imposters in human skin.","TWN":"聽說人類要入侵才來的，結果卻只有這些擬人的怪物。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"이 녀석들의 팔에 뭔가 새겨져 있습니다.","JPN":"こいつらの腕に何かが刻み付けられています。","ENG":"There’s some kind of mark on their arms.","TWN":"這些傢伙的手臂上刻著什麼東西。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"처치한 놈들은 전부 이런 표식이 있는 것 같은데, 무슨 의미라도 있는 걸까요?","JPN":"やっつけたやつらは全部このような印があるみたいですけど、何か意味でもあるのでしょうか？","ENG":"I think they all have it. Do you think it means anything?","TWN":"被消滅的傢伙好像都有這種標記，這有什麼意義嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이건…….","JPN":"これは……","ENG":"That’s...","TWN":"這是…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"검은 역병에 걸린 인간들에게 새겨지는 추방자의 낙인이군요.","JPN":"黒い疫病にかかった人間に刻まれる追放者の烙印ですね。","ENG":"A brand marked to humans who’ve contracted the Black Plague.","TWN":"被黑死病感染的人類身上刻下的流放者的烙印。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무래도 이분들은 자신의 의지로 여기까지 온 게 아닌 것 같네요.","JPN":"どうやらこの方々は、自分の意志でここまで来たわけではないようです。","ENG":"Someone must have forced them to come here against their will.","TWN":"看來這些人不是自願來到這裡的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"병자들을 이용해서 이곳을 공격할 생각을 하다니, 아무리 인간이라지만 끔찍한 발상이군요.","JPN":"病人を利用してここを攻撃しようとするとは、いくら人間であっても残酷な発想です。","ENG":"Using the sick as an army... What a nasty human way of thinking.","TWN":"竟然想著利用病人來攻擊這裡，這想法真可怕。雖然是人類，但也太殘忍了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_NPC_NULL_WARRIOR","text":{"KOREA":"검은 역병에 걸리면… 우리도 결국 이렇게 되고 마는 걸까요?","JPN":"黒い疫病にかかると……俺たちも結局こうなってしまうのでしょうか？","ENG":"If we also get the Black Plague... Do we also end up like this?","TWN":"如果感染了黑死病…我們最後也會變成這樣嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"자, 그런 걱정은 나중에. 우리에겐 아직 지켜야 할 것이 남아있잖습니까?","JPN":"さて、そのような心配は後でしてください。私たちにはまだ守るべきものが残っているではないですか。","ENG":"That’s a worry for another time. Right now, we have our duties to protect what’s ours.","TWN":"好了，現在想這些也沒用。我們還有需要守護的東西，不是嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이만 돌아가도록 하죠.","JPN":"もう帰りましょう。","ENG":"Let’s head back.","TWN":"回去吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_NPC_NULL_DOCTOR","text":{"KOREA":"도, 도마님… 해질 무렵부터 동생 분의 상태가 이상하더니…","JPN":"ど、ドマ様……夕方から妹さんの容態がおかしくなって……","ENG":"D-Doma...! Your sister... she suddenly started getting worse during sunset and...","TWN":"多，多馬先生…你妹妹從下午開始狀態就變得有點奇怪…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_NPC_NULL_DOCTOR","text":{"KOREA":"갑자기 모습이 검게 변해서… 어떤 냄새가 난다며 밖으로 뛰쳐나가셨어요.","JPN":"いきなり全身が黒くなっては……ある匂いがすると外に出ていきました。","ENG":"She ran out, saying she smelled something as she turned black.","TWN":"身體突然變黑了…又說聞到什麼味道，就跑出去了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"어느 방향으로 갔는지… 저에게 알려 주시겠습니까?","JPN":"どの方向に向かったのか……私に教えてくれませんか？","ENG":"Can you tell me which way she went?","TWN":"她往哪個方向去了？你能告訴我嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"그거 알아, 오빠?","JPN":"それ知ってる？　兄さん。","ENG":"You know what, Doma?","TWN":"你知道嗎，哥哥？"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"흡혈귀 전사들은 자신이 죽을 때가 되면, 함께 싸운 동료 전사나 자신이 인정한 호적수에게 그 심장을 먹게 해.","JPN":"吸血鬼の戦士は自分が死ぬ時になると、一緒に戦った戦士の仲間や自分が認めた好敵手にその心臓を食わせるの。","ENG":"When a vampire warrior is about to die, they seek out their comrades or a formidable foe and have their heart consumed.","TWN":"吸血鬼戰士在臨死之際，會讓與自己並肩作戰的戰友，或自己認可的對手吃掉自己的心臟。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 하면, 두 사람 모두 치명상을 입더라도 한 명은 살 수 있게 되거든.","JPN":"そうすると、二人とも致命傷を負っても一人は生き残れるから。","ENG":"That way, when both get badly injured, at least one of them can survive.","TWN":"這樣的話，即使兩個人都受了致命傷，也能保住一個人的性命。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"삶은 영원하지 못하더라도, 심장을 통해 영혼만은 영원히 누군가를 통해 이어가게 되는 거야.","JPN":"人生は永遠でなくても、心臓を通じて魂だけは永遠に誰かを通じて繋がれるんだよ。","ENG":"Although life does not last forever, the soul within the heart does.","TWN":"即使生命不是永恆的，靈魂也會透過心臟永遠傳承給某個人。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"미신이라는 것쯤은 알지만, 그래도 멋진 이야기지 않아?","JPN":"迷信ってことくらいはわかってるけど、それでも素敵な話だと思わない？","ENG":"I realize it's a silly superstition, but isn't it wonderful still?","TWN":"雖然知道這只是迷信，但這故事不是很棒嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"병이 나아서 오빠랑 전쟁터에 나가게 된다면, 나는 오빠에게 내 심장을 맡길게.","JPN":"病気が治って兄さんと戦場に出ることになったら、私は兄さんに私の心臓を託すよ。","ENG":"If I ever beat this disease and go out on the battlefield with you, I want you to take my heart.","TWN":"如果我病好了能和哥哥一起上戰場的話，我會把我的心臟交給哥哥。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐… 오빠가 나보다 먼저 쓰러질 일은 없겠지만 말이야.","JPN":"まあ……兄さんより私が先に倒れることはないでしょうけど。","ENG":"Even though... it’s highly unlikely that you’ll go down before I do.","TWN":"不過… 哥哥應該不會比我先倒下。"},"stage":{"bg":"SKY_NIGHT","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"큭큭… 피냄새를 뚫고 멀리서부터 익숙한 악취가 나더라니…","JPN":"ククッ……血の匂いの中で慣れている悪臭がしてきたと思ったら……","ENG":"Keke... I was wondering why that foul stench smelled so familiar.","TWN":"咳咳…穿過血腥味，從遠處就聞到了這熟悉的惡臭…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"네놈이었냐?","JPN":"貴様だったのか？","ENG":"So we meet again.","TWN":"是你嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"꽤나 많이 다치신 것 같군요.","JPN":"結構大怪我をしているようですね。","ENG":"My, you seem to be barely hanging on.","TWN":"看起來你傷得不輕啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"쿨럭……","JPN":"ガハッ……","ENG":"Kuh...!","TWN":"咳咳…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"이대로 허무하게 죽겠구나 싶었는데……","JPN":"このまま虚しく死ぬかと思ったけど……","ENG":"And here I thought I was going to die a boring death...","TWN":"我以為我會就這樣死去…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"마지막 순간에 널 만나다니, 나도 운이 아주 나쁘지는 않은 것 같네.","JPN":"最後の瞬間にあんたに出会うなんて、私の運もそう悪くはないみたいだ。","ENG":"But seeing you just before my death... I guess my luck isn’t that bad after all.","TWN":"能在最後一刻遇見你，我的運氣也不算太差。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……그 검은 상처, 단순한 결투로 생긴 것은 아니군요.","JPN":"……その黒い傷、ただの決闘で負ったものではないですね。","ENG":"...That black wound. That’s not from a normal fight.","TWN":"…那黑色的傷口，不是單純的決鬥造成的吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"못 본 사이에 당신도 검은 역병에 걸린 겁니까? 상태가 심각해 보이네요.","JPN":"見ない間に、あなたも黒い疫病にかかったのですか？　ひどい状態ですね。","ENG":"Did the Black Plague get to you while we haven’t seen each other? It looks pretty serious.","TWN":"好久不見，你也感染了黑死病嗎？看起來情況很嚴重啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"흥, 이 정도는 아무것도 아니야. 그보다 약속이나 지켜.","JPN":"ふん、このくらいはどうってことない。それより、約束を守れ。","ENG":"Hmph! Nothing you should worry about. But you need to keep your promise to me.","TWN":"哼，這點程度對我來說不算什麼。比起這個，還是遵守約定吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"약속?","JPN":"約束？","ENG":"Promise?","TWN":"約定？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그래, 벌써 잊은 건 아니겠지?","JPN":"ああ、もう忘れたわけじゃないだろう？","ENG":"Did you already forget?","TWN":"對，你不會已經忘了吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"결투.","JPN":"決闘。","ENG":"The duel.","TWN":"決鬥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"다음에 만나면 다시 한번 결투를 하기로 말이야.","JPN":"今度会ったらもう一度決闘するって決めたじゃないか。","ENG":"You said you’d fight me again the next time we met.","TWN":"再次見面的話，再來一場決鬥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그건 공정하지 못하군요. 그런 검은 역병에 다 썩어가는 몸으로 저와 싸우겠단 말입니까?","JPN":"それは不公正ですね。黒い疫病で腐れかかっているその体で、私と戦うつもりなのですか？","ENG":"But this fight’s too one-sided. Are you seriously thinking of challenging me with your rotting body?","TWN":"那可不公平啊。你打算用那被黑死病腐蝕的身體和我戰鬥嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"날 우습게 보지 마.","JPN":"アタシをなめるな。","ENG":"You underestimate me.","TWN":"不准小看我。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"전사라면, 진정한 적수를 만났을 때 싸워야만 하는 거야.","JPN":"戦士なら、真なる敵に出くわした時戦わなければいけない。","ENG":"As a warrior, I can’t pass up a fight with a formidable foe like you.","TWN":"作為戰士，必須在遇到真正的對手時戰鬥。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"병에 걸려 추하게 죽어갈 바엔… 그렇게 전사로서 싸우다 죽는 게, 훨씬 의미 있다고.","JPN":"病気にかかって惨めに死んでいくよりは……そうやって戦士として戦って死ぬのが、ずっと意味があるんだよ。","ENG":"Instead of dying pathetically by this disease... I’d rather die in battle, with honor.","TWN":"與其病死，死得那麼難看…還不如作為戰士戰鬥到死，這樣更有意義。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그러니까… 네가 정말 피도 눈물도 없는 흡혈귀라면…!","JPN":"だから……あんたが本当に血も涙もない吸血鬼なら……！","ENG":"So... If you really are a heartless vampire like they say...!","TWN":"所以…如果你真是個沒血沒淚的吸血鬼的話…！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그런 동정하는 눈빛으로 쳐다보지 말고 나랑 싸워!","JPN":"そんな同情するような目で見てないで、アタシと戦え！","ENG":"Then stop pitying me and fight me!","TWN":"不要用那種同情的眼神看著我，跟我戰鬥吧！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"명예로운 죽음이라… 어차피 죽을 거라면 그것도 나쁘진 않겠네요.","JPN":"名誉ある死ですか……どうせ死ぬなら、それも悪くありませんね。","ENG":"An honorable death, you say? I don’t think that’s a bad way to die.","TWN":"光榮的死亡嗎…反正都要死了，戰死可能更有意義吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그 전에 묻고 싶은 것이 있군요.","JPN":"その前に聞きたいことがあります。","ENG":"But before, I want to ask you something.","TWN":"在那之前，我有個問題想問你。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"조금 전 당신과 싸웠던 그 괴물은…… 어땠습니까?","JPN":"さっきあなたと戦っていたその化け物は……いかがでしたか？","ENG":"The monster you fought just before... How was it?","TWN":"剛才和你戰鬥的那個怪物…怎麼樣了？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"강했나요?","JPN":"手強かったですか？","ENG":"Was she strong?","TWN":"很強嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신의 결투 상대로서, 부족함이 없었나요?","JPN":"あなたの決闘相手として、十分でしたか？","ENG":"Was the monster worthy enough to be your opponent?","TWN":"作為你的對手，沒有讓你失望吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"간만에 겨뤄볼 만한 상대였지.","JPN":"久しぶりに戦い甲斐のある相手だった。","ENG":"One of the strongest foes I’ve ever faced.","TWN":"難得遇到一個值得較量的對手。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"놀라운 사격 솜씨에 뛰어난 근접 전투술까지.","JPN":"素晴らしい射撃の腕に、優れた近接戦能力まで。","ENG":"Who would’ve thought a gunslinger could also be an expert in hand-to-hand combat?","TWN":"驚人的射擊技巧和出色的近戰技術。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그러고 보니 묘하게 너와 비슷한 느낌이었어.","JPN":"そういえば、妙にあんたと似ていたな。","ENG":"Come to think of it, fighting her was akin to fighting you.","TWN":"這麼說來，感覺和你有點像呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"서로 몸이 이 꼴만 아니었다면 끝내주는 대결이 됐을지도 모르지.","JPN":"お互いこの様じゃなかったら、見事な対決になったのかもしれない。","ENG":"It would’ve been a more glorious fight if we hadn't both been in such bad shape from the disease.","TWN":"如果我們彼此的身體不是這副模樣，或許會是一場精彩的對決。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……그랬군요.","JPN":"……そうだったのですか。","ENG":"...I see.","TWN":"…原來如此。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇다면 이걸 받으시죠.","JPN":"それなら、これをどうぞ。","ENG":"Then I want you to take this.","TWN":"那麼請收下這個吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그 괴물의 심장을…? 무슨 속셈이지?","JPN":"あの化け物の心臓を……？　どういうつもりだ？","ENG":"The monster’s heart...? What are you trying to do with it?","TWN":"那個怪物的心臟…？你要幹什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이래봬도 영생을 가져다준다는 고위 흡혈귀의 심장이랍니다. 어쩌면, 이게 당신의 목숨을 살릴지도 모르죠.","JPN":"こう見えても永生をもたらしてくれる高位の吸血鬼の心臓です。もしかしたら、これがあなたを生かせてくれるかもしれません。","ENG":"It’s the heart of a high-class vampire that’ll grant you eternal life. Perhaps this could save you.","TWN":"別看它這樣，這是能帶來永生的高階吸血鬼心臟。也許，它能救你的命。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"다행히 아직 검은 역병이 심장까지 뻗치지는 않았더군요.","JPN":"幸い、まだ黒い疫病が心臓まではたどり着いていませんでした。","ENG":"Fortunately, the Black Plague hasn’t reached her heart.","TWN":"幸好黑死病還沒有蔓延到心臟。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 아이는 완전히 변해버리기 전에, 당신과 싸우다가 죽기를 택한 거겠죠.","JPN":"この子は完全に変貌する前に、あなたと戦って死ぬことを選んだのでしょう。","ENG":"I believe she chose to die fighting you before it completely consumed her.","TWN":"她在完全變異之前，選擇了和你戰鬥到死吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"뭐야. 네 동족이었나? 어쩐지 비슷한 냄새가 나더라니.","JPN":"何だ。あんたの同族だったのか？　どうりで似たような匂いがしたんだな。","ENG":"Huh? Was she your kin? Now I see why she smelled so familiar.","TWN":"什麼啊，你是她的同類嗎？難怪有相似的氣味。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"…그럼 왜 내게 동족의 복수를 하지 않는 거냐?","JPN":"……それじゃ、どうしてアタシに同族の復讐をしない？","ENG":"...Wait, why aren’t you going to avenge your kin?","TWN":"…那你為什麼不向我報仇呢？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신도 알고 있잖습니까?","JPN":"あなたもわかっているではないですか。","ENG":"I’m sure you know why.","TWN":"你不是知道嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"두 전사들의 명예로운 결투였습니다. 그 사이에 시시콜콜한 복수 따위를 들이밀 순 없죠.","JPN":"二人の戦士の名誉ある決闘でした。そこにくだらない復讐などを突きつけるわけにはいきません。","ENG":"It was an honorable battle between two warriors. Petty vengeance has no place in this.","TWN":"這是兩位戰士之間的光榮決鬥。在這種情況下，不能摻雜無聊的報仇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"큭큭, 혼자 잘난 듯 떠들어대는 혀는 여전하군.","JPN":"ククッ、偉そうに喋るその舌は相変わらずだな。","ENG":"Keke... I see that sly tongue of yours still works.","TWN":"咳咳，你那自以為是的嘴巴還是老樣子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그게 동족의 심장까지 바쳐가며 날 살려주겠단 이유인가?","JPN":"それが同族の心臓を捧げてまでアタシを助けてくれる理由なのか？","ENG":"Then what’s your reason for giving up your kin's heart to save me?","TWN":"那就是你甘願獻出同族的心臟來救我的理由嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 심장은, 소원을 이루어 준 것에 대한 보답입니다.","JPN":"この心臓は、願いを叶えてくれたお礼です。","ENG":"I give this to you because... you made her wish come true.","TWN":"這顆心臟，是對實現願望的回報。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 아이… 꼭 당신과 싸워보고 싶어 했거든요.","JPN":"この子……あなたと戦ってみたいと思っていたのです。","ENG":"She told me... that she wanted to fight you before she died.","TWN":"她…一直想和你一較高下呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"역병에 시달리는 병자가 아닌, 한 명의 전사로서 말입니다.","JPN":"疫病に苦しむ病人ではなく、一人の戦士として。","ENG":"She desired to die as a warrior, not as a plague-ridden sick.","TWN":"不是作為受黑死病折磨的病人，而是作為一名戰士。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 심장을 먹는다면, 당신에게 프레데릭의 이름을 내리겠습니다.","JPN":"この心臓を食べるなら、あなたにフレドレックの名を授けましょう。","ENG":"If you choose to eat that heart, I will bestow you the Frederick name.","TWN":"如果你吃下這顆心臟，我將賜予你弗雷德里克家族的名字。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘 훌륭한 전사를 하나 잃었으니, 당신이 그 빈 자릴 채우는 것도 나쁘지 않겠죠.","JPN":"今日立派な戦士を一人失ったのですから、あなたがその空席を埋めることも悪くないでしょうね。","ENG":"Today, we lost a great warrior. But it wouldn't be so bad if we could be greeted with a new warrior.","TWN":"今天失去了一位優秀的戰士，由你來填補這個空缺也不錯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"날 살리는 대가로 일족으로 받아들이겠다는 거냐?","JPN":"アタシを助ける対価として、一族に受け入れるってことか？","ENG":"So you want me to join your tribe to save my life?","TWN":"救我一命的代價是讓我加入你們一族嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"……재미있군.","JPN":"……面白い。","ENG":"...Funny.","TWN":"…有意思。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그래서, 내 새로운 이름은 뭐지?","JPN":"それで、アタシの新しい名前は何だ？","ENG":"Okay, then what will be my new name?","TWN":"那麼，我的新名字是什麼？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신에겐 이름이 이미 있을 텐데요?","JPN":"あなたにはすでに名前があるでは？","ENG":"I thought you already had a name?","TWN":"你應該已經有名字了吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"그건 어릴 적 인간들이 나한테 멋대로 지어준 이름이야.","JPN":"それは幼い頃に人間が勝手にアタシにつけた名前だ。","ENG":"That was one the humans gave me when I was little.","TWN":"那是小時候人類隨便給我取的名字。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"라이칸스로프에겐 이름 짓는 전통따윈 없으니까, 결투를 위해 그걸 그대로 쓰고 있었을 뿐이지.","JPN":"ライカンスロープには名前を付けるしきたりなどないから、決闘のためにそれをそのまま使っていただけだよ。","ENG":"Lycanthrope don’t have a custom of naming their offspring. I'm just using it for convenience during dueling.","TWN":"狼人沒有取名字的傳統，所以我只是為了決鬥而用這個名字而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"하지만 이젠…","JPN":"だけど、もう……","ENG":"But now...","TWN":"但現在…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMA_WOLF_NULL_NAME","text":{"KOREA":"이름을 가져야 할 다른 이유가 생겼으니까.","JPN":"名前を持たないといけない、別の理由ができたからな。","ENG":"I have a reason to have a name.","TWN":"有了必須取名字的理由。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저희 흡혈귀들은 가문의 새로운 일원에게 생전 뛰어났던 전사의 이름을 물려주곤 한답니다.","JPN":"私たち吸血鬼は家門の新しい一員に、生前優秀であった戦士の名前を伝えます。","ENG":"We vampires usually give names of valiant warriors to our newcomers.","TWN":"我們吸血鬼一族會將生前最出色戰士的名字傳給家族的新成員。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그러니 괜찮다면 당신에게도 전사의 이름을 드리도록 하죠.","JPN":"ですから、よかったらあなたにも戦士の名前を与えましょう。","ENG":"So if it’s okay with you, I’d like to give you a name of a warrior.","TWN":"所以，如果你不介意的話，我也會給你一個戰士的名字。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"유마.","JPN":"ユマ。","ENG":"Yuma.","TWN":"游馬。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"당신의 이름은 프레데릭 유마입니다.","JPN":"あなたの名前はフレドレック・ユマです。","ENG":"From now on, your name is Frederick\xA0Yuma.","TWN":"你的名字是弗雷德里克·游馬。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"HOUSE_OF_THE_RISING_SUN_02_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"그럼 이제부터 어떻게 할 셈이야? 흡혈귀들의 환영 의식이라도 치러야 하나?","JPN":"じゃあ、これからどうするつもりだ？　吸血鬼の歓迎儀式でも行われるのか？","ENG":"So, what happens next? Is there a ritual or something I need to go through?","TWN":"那接下來呢？是要舉行吸血鬼的歡迎儀式嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……원한다면 네가 온 곳으로 돌아가도 상관없다.","JPN":"……望むならあなたが来たところに戻っても構わない。","ENG":"...You can go back to your home, if you want.","TWN":"…如果想回你的故鄉也可以，我沒意見。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"……동생아.","JPN":"……妹よ。","ENG":"...Little sister.","TWN":"…妹妹。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"내 고향은 진작에 검은 역병에 집어삼켜졌어.","JPN":"アタシの故郷はもう黒い疫病に飲み込まれた。","ENG":"I don’t have one. My home was taken away by the Black Plague.","TWN":"我的故鄉早已被黑死病吞噬了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"돌아가봐야 날 기다리는 건 검게 썩어버린 시체들뿐이겠지.","JPN":"帰ってもアタシを待ってるのは黒く腐ってしまった死体だけだろう。","ENG":"All that awaits me there are rotten corpses.","TWN":"回去後等待我的應該只有那些腐爛發黑的屍體吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"오빠는 어쩔래?","JPN":"兄さんはどうする？","ENG":"What do you want to do, Doma?","TWN":"哥哥你打算怎麼辦？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"이대로 영지로 돌아가서, 남은 일족들을 지킬 거야?","JPN":"このまま領地に戻って、残った一族を守るのか？","ENG":"Are you heading back home to protect what’s left of your tribe?","TWN":"回到領地，保護剩下的族人嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아니.","JPN":"いいや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"지키는 것만으로는 아무 것도 변하지 않아.","JPN":"守るだけでは何も変わらない。","ENG":"Just protecting them won’t change anything.","TWN":"僅僅守護是無法改變任何事情的。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"한 곳에 머물러 있는 것만으로는 원하는 걸 지킬 수 없어.","JPN":"一か所に止まっているだけでは、欲しいものを守れないのだ。","ENG":"I can’t protect them by staying here.","TWN":"僅僅停留在一個地方是無法守護你想要的東西的。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"나는 북쪽으로 향할 거다.","JPN":"私は北の方へ向かう。","ENG":"I’m going to head north.","TWN":"我要去北方。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그곳에서 힘을 얻어, 이 역병을 퍼트린 원흉을 찾아낼 거다.","JPN":"あそこで力を得て、この疫病を広めた元凶を探し出す。","ENG":"There, I will obtain the power I seek to discover the origin of this plague.","TWN":"在那裡獲得力量，找到傳播這場瘟疫的罪魁禍首。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그리고……","JPN":"そして……","ENG":"And...","TWN":"然後…"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그 존재에게 결투를 신청할 거란다.","JPN":"その存在に決闘を申し込むつもりだよ。","ENG":"I’ll request a duel with whatever being is there.","TWN":"我要向那個存在發起決鬥。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"명예도 정의도 없는, 오직 피와 눈물만이 남을 결투를.","JPN":"名誉も正義もない、ただ血と涙だけが残る決闘を。","ENG":"A duel devoid of honor and justice... but drenched in blood and tears.","TWN":"這將是一場沒有榮譽和正義，只有血與淚的決鬥。"},"stage":{"bg":"DOMA_01","bgm":"HOUSE_OF_THE_RISING_SUN_01_MR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};